	DisruptionReason string `json:"disruption_reason,omitempty"`
	// OutcomeReason carries the machine-readable lifecycle classification for
	// the attempt outcome. It complements Disrupted/DisruptionReason without

 47	// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
 48	// before claim in the work / execute-loop paths. The hook evaluates the bead
 49	// using the repository's triage prompt and returns one of the typed intake
 50	// outcomes so the loop can decide whether to claim or skip the candidate.
 51	//
 52	// The hook preserves operator-supplied passthrough constraints. When the
 53	// resolved route cannot satisfy the strong splitter floor, it returns an
 54	// actionable-but-blocking result with agent_power_unsatisfied in the detail so
 55	// the loop can skip the bead instead of attempting weak decomposition.
 56	func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
 57		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
 58			if ctx != nil {
 59				if err := ctx.Err(); err != nil {
 60					return PreClaimIntakeResult{}, err
 61				}
 62			}
 63			if strings.TrimSpace(projectRoot) == "" {
 64				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
 65			}
 66			if !hasBeadLifecycleSkill(projectRoot) {
 67				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: skill missing: bead-lifecycle")
 68			}
 69			if store == nil {
 70				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
 71			}
 72	
 73			b, err := store.Get(beadID)
 74			if err != nil {
 75				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
 76			}
 77	
 78			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
 79			if err != nil {
 80				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
 81			}
 82	
 83			strongMinPower := resolveStrongSplitterMinPower(ctx, projectRoot, svc)
 84			if rcfg.MinPower() > strongMinPower {
 85				strongMinPower = rcfg.MinPower()
 86			}
 87	
 88			result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
 89				Prompt:           prompt,
 90				WorkDir:          projectRoot,
 91				PromptSource:     PreClaimIntakePromptSource,
 92				MinPowerOverride: strongMinPower,
 93			})
 94			if err != nil {
 95				if isStrongPowerUnsatisfiedError(err) {
 96					return PreClaimIntakeResult{
 97						Outcome: PreClaimIntakeAmbiguousNeedsHuman,
 98						Detail:  "agent_power_unsatisfied: " + err.Error(),
 99					}, nil
100				}
101				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: dispatch: %w", err)
102			}
